+template<int M = 32, int WARPSIZE = 32>
+__device__ void _cupy_channelizer_32x32_complex128_complex128( const int n_chans,
+                                                               const int n_taps,
+                                                               const int n_pts,
+                                                               const cuDoubleComplex *__restrict__ x,
