+        // Load data
+        if ( bid >= n_taps ) {
+            if ( btx < n_chans && ty < n_taps ) {
+                s_reg[tx][( n_taps - 1 ) - ty] = x[( ( bid - n_taps + 1 ) + ty ) * n_chans + ( n_chans - 1 - btx )];
+            }
+        } else {
+            if ( btx < n_chans && ty <= bid ) {
+                s_reg[tx][bid - ty] = x[ty * n_chans + ( n_chans - 1 - btx )];
+            } else {
