+		reinterpret_cast<T*>(
+			&s_zi[n_sections * zi_width]) };
+
+	const int tx { static_cast<int>( threadIdx.x ) };
+	const int ty {
+		static_cast<int>( blockIdx.y * blockDim.y + threadIdx.y ) };
+
+	// Reset shared memory
+	s_out[tx] = 0;
+
+	// Load zi
+	for ( int i = 0; i < zi_width; i++ ) {
+		s_zi[tx * zi_width + i] =
+			zi[ty * n_sections * zi_width + tx * zi_width + i ];
+	}
