+		for ( int n = 0; n < load_size; n++ ) {
+			if ( tx == 0 ) {
+				x_n = x_in[ty * n_samples + n];
+			} else {
+				x_n = s_out[tx - 1];
+			}
+
+			// Use direct II transposed structure
+			temp = s_sos[tx * sos_width + 0]
+				* x_n + s_zi[tx * zi_width + 0];
+
+			s_zi[tx * zi_width + 0] =
