+
+template<typename T>
+__device__ void _cupy_upfirdn1D(
+		const T * __restrict__ inp,
+		const T * __restrict__ h_trans_flip,
+		const int up,
+		const int down,
+		const int axis,
+		const int x_shape_a,
+		const int h_per_phase,
+		const int padded_len,
+		T * __restrict__ out,
+		const int outW) {
+
+	const int t {
+		static_cast<int>(blockIdx.x * blockDim.x + threadIdx.x) };
+	const int stride { static_cast<int>(blockDim.x * gridDim.x) };
+
+	for ( size_t tid = t; tid < outW; tid += stride ) {
+		int x_idx { static_cast<int>((tid * down) / up) % padded_len };
+		int h_idx { (tid * down) % up * h_per_phase };
+		int x_conv_idx { x_idx - h_per_phase + 1 };
+
+		if ( x_conv_idx < 0 ) {
+			h_idx -= x_conv_idx;
+			x_conv_idx = 0;
+		}
+
+		T temp {};
+
+		for ( int x_c = x_conv_idx; x_c < (x_idx + 1); x_c++ ) {
+			if ( x_c < x_shape_a && x_c >= 0 ) {
+				temp += inp[x_c] * h_trans_flip[h_idx];
+			}
+			h_idx += 1;
+		}
+		out[tid] = temp;
+	}
+}
+
+extern "C" __global__ void _cupy_upfirdn1D_float32(
+	const float * __restrict__ inp,
+	const float * __restrict__ h_trans_flip,
+	const int up,
+	const int down,
+	const int axis,
+	const int x_shape_a,
+	const int h_per_phase,
+	const int padded_len,
+	float * __restrict__ out,
+	const int outW
+	) {
+	_cupy_upfirdn1D<float>(inp, h_trans_flip, up, down, axis, x_shape_a, h_per_phase, padded_len, out, outW);
+}
+
+extern "C" __global__ void _cupy_upfirdn1D_float64(
+	const double * __restrict__ inp,
+	const double * __restrict__ h_trans_flip,
+	const int up,
+	const int down,
+	const int axis,
