+#include <thrust/complex.h>
+
+///////////////////////////////////////////////////////////////////////////////
+//                              CONVOLVE                                     //
+///////////////////////////////////////////////////////////////////////////////
+
+template <typename T>
+__device__ void _cupy_convolve(
+		const T * __restrict__ inp,
+		const int inpW,
+		const T * __restrict__ kernel,
+		const int kerW,
+		const int mode,
+		const bool swapped_inputs,
+		T * __restrict__ out,
+		const int outW) {
+
+	const int tx {
+		static_cast<int>( blockIdx.x * blockDim.x + threadIdx.x ) };
+	const int stride { static_cast<int>( blockDim.x * gridDim.x ) };
+
+	for ( int tid = tx; tid < outW; tid += stride ) {
+
+		T temp {};
+
+		if ( mode == 0 ) {  // Valid
+			if ( tid >= 0 && tid < inpW ) {
+				for ( int j = 0; j < kerW; j++ ) {
+					temp += inp[tid + j] * kernel[( kerW - 1 ) - j];
+				}
+			}
+		} else if ( mode == 1 ) {   // Same
+			const int P1 { kerW / 2 };
+			int start {};
+			if ( !swapped_inputs ) {
+				start = 0 - P1 + tid;
+			} else {
+				start = ( ( inpW - 1 ) / 2 ) - ( kerW - 1 ) + tid;
+			}
+			for ( int j = 0; j < kerW; j++ ) {
+				if ( ( start + j >= 0 ) && ( start + j < inpW ) ) {
+					temp += inp[start + j] * kernel[( kerW - 1 ) - j];
+				}
+			}
+		} else {    // Full
+			const int P1 { kerW - 1 };
+			int start { 0 - P1 + tid };
+			for ( int j = 0; j < kerW; j++ ) {
+				if ( ( start + j >= 0 ) && ( start + j < inpW ) ) {
+					temp += inp[start + j] * kernel[( kerW - 1 ) - j];
+				}
+			}
+		}
+
+		out[tid] = temp;
+	}
+}
+
+extern "C" __global__ void _cupy_convolve_int32(
+	const int * __restrict__ inp,
+	const int inpW,
+	const int * __restrict__ kernel,
+	const int kerW,
+	const int mode,
+	const bool swapped_inputs,
+	int * __restrict__ out,
