+///////////////////////////////////////////////////////////////////////////////
+//                              CONVOLVE 2D                                  //
+///////////////////////////////////////////////////////////////////////////////
+
+template<typename T>
+__device__ void _cupy_convolve2D(
+		const T * __restrict__ inp,
+		const int inpW,
+		const int inpH,
+		const T * __restrict__ kernel,
+		const int kerW,
+		const int kerH,
+		const int S0,
+		const int S1,
+		T * __restrict__ out,
+		const int outW,
+		const int outH,
+		const int pick) {
+
+	const int ty {
+		static_cast<int>(blockIdx.x * blockDim.x + threadIdx.x) };
+	const int tx {
+		static_cast<int>(blockIdx.y * blockDim.y + threadIdx.y) };
+
+	int i {};
+	if ( pick != 3 ) {
+		i = tx + S0;
+	} else {
+		i = tx + S1;
+	}
+	int j { ty + S0 };
+
+	int2 oPixelPos {tx, ty};
+	if ( (tx < outH) && (ty < outW) ) {
+		T temp {};
+
+		// Odd kernel
+		if ( pick == 1) {
+			for (int k = -S0; k < (S0 + 1); k++){
+				for (int l = -S0; l < (S0 + 1); l++) {
+					int2 iPixelPos {(i + k), (j + l)};
+					int2 coefPos {(-k + S0), (-l + S0)};
+					temp += inp[iPixelPos.x * inpW + iPixelPos.y] *
+						kernel[coefPos.x * kerW + coefPos.y];
+				}
+			}
+		// Even kernel
+		} else if (pick == 2) {
+			for (int k = -S0; k < S0; k++){
+				for (int l = -S0; l < S0; l++) {
+					int2 iPixelPos {(i + k), (j + l)};
+					int2 coefPos {(-k + S0 - 1), (-l + S0 - 1)};
+					temp += inp[iPixelPos.x * inpW + iPixelPos.y] *
+						kernel[coefPos.x * kerW + coefPos.y];
+				}
+			}
+
+		// Non-squares kernel
+		} else {
+			for (int k = 0; k < S0; k++){
+				for (int l = 0; l < S1; l++) {
+					int2 iPixelPos {(i + k - S1), (j + l - S0)};
+					int2 coefPos {(-k + S0 - 1), (-l + S1 - 1)};
+					temp += inp[iPixelPos.x * inpW + iPixelPos.y] *
+						kernel[coefPos.x * kerH + coefPos.y];
+				}
+			}
+		}
+		out[oPixelPos.x * outW + oPixelPos.y] = temp;
+	}
+}
