+					int2 iPixelPos {(i + k), (j + l)}; // iPixelPos[1], [0]
+					int2 coefPos {(k + S0), (l + S0)};
+					temp += inp[iPixelPos.x * inpW + iPixelPos.y] *
+						kernel[coefPos.x * kerW + coefPos.y];
